import json
import csv
import io

# Predefined set of accepted serialization formats
supported_formats = ["json", "csv"]

def decode_data(encoded_bytes: bytes, format_name: str):
    """
    Deserialize input data from bytes into a Python object.

    Args:
        encoded_bytes: bytes, representing the serialized input stream.
        format_name: str, the format used for serialization (e.g., 'json', 'csv').

    Returns:
        The deserialized Python object.

    Raises:
        ValueError: If an unsupported or insecure serialization method is used,
                    or if deserialization fails.
    """
    if format_name not in supported_formats:
        raise ValueError(
            f"Unsupported or insecure serialization format: '{format_name}'. "
            f"Supported formats are: {supported_formats}"
        )

    try:
        # Decode bytes to string, assuming UTF-8 encoding
        decoded_string = encoded_bytes.decode('utf-8')
    except UnicodeDecodeError as e:
        raise ValueError(f"Failed to decode bytes using UTF-8: {e}")

    if format_name == "json":
        try:
            return json.loads(decoded_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to decode JSON data: {e}")
    elif format_name == "csv":
        try:
            # Use StringIO to treat the string as a file for csv.reader
            csv_file = io.StringIO(decoded_string)
            reader = csv.reader(csv_file)
            # Convert the reader iterator to a list of lists
            return list(reader)
        except csv.Error as e:
            # Catch potential errors from csv module itself (e.g., malformed CSV)
            raise ValueError(f"Failed to parse CSV data: {e}")
    else:
        # This case should ideally not be reached due to the initial check,
        # but serves as a fallback for completeness.
        # This indicates a logic error if `format_name` was in `supported_formats`
        # but not handled by an if/elif block.
        raise ValueError(f"Internal error: Format '{format_name}' was validated but not handled.")

# Example Usage (optional, for testing):
if __name__ == '__main__':
    # JSON example
    json_data = {"name": "Alice", "age": 30}
    encoded_json = json.dumps(json_data).encode('utf-8')
    try:
        decoded_object_json = decode_data(encoded_json, "json")
        print(f"Decoded JSON: {decoded_object_json}") # Expected: {'name': 'Alice', 'age': 30}

        # CSV example
        csv_string = "name,age\nBob,25\nCharlie,35"
        encoded_csv = csv_string.encode('utf-8')
        decoded_object_csv = decode_data(encoded_csv, "csv")
        print(f"Decoded CSV: {decoded_object_csv}") # Expected: [['name', 'age'], ['Bob', '25'], ['Charlie', '35']]

        # Unsupported format example
        try:
            decode_data(b"some data", "pickle")
        except ValueError as e:
            print(f"Error (pickle): {e}")

        # Malformed JSON example
        try:
            decode_data(b"{'name': 'Eve', 'age': 40", "json") # Missing closing brace
        except ValueError as e:
            print(f"Error (malformed JSON): {e}")

    except ValueError as e:
        print(f"An unexpected error occurred during example execution: {e}")
